// Helper to create mock board
function createMockBoard(tileDefinitions) {
  var tiles = {};
  for (var pos in tileDefinitions) {
    tiles[pos] = tileDefinitions[pos];
  }
  return {
    getTile: function(pos) {
      return tiles[pos] || { type: 'empty', isSafeZone: false };
    },
    getPath: jest.fn().mockImplementation(function(currentPos, steps) {
      // Simplified path: linear advance, if beyond 60 wrap or stop
      var newPos = currentPos + steps;
      if (newPos > 60) newPos = 60; // cap for tests
      return newPos;
    })
  };
}

// Helper to create player state
function createPlayer(playerId, opts) {
  opts = opts || {};
  return {
    playerId: playerId,
    tokens: [
      { tokenId: playerId + '-t0', position: opts.startPos || 0, atk: 0, frozenRounds: 0 },
      { tokenId: playerId + '-t1', position: (opts.startPos||0)+1, atk: 0, frozenRounds: 0 },
      { tokenId: playerId + '-t2', position: (opts.startPos||0)+2, atk: 0, frozenRounds: 0 }
    ],
    elementQueue: [],
    elementAffinity: opts.affinity || 'fire',
    character: { atk: 30, mag: 10 },
    tileGainMultiplier: 1,
    mag: 0,
    hp: 1000,
    level: 3,
    comboCount: 0,
    emptyTileVisits: 0,
    consecutiveRollsThisTurn: 0,
    doubleRollCooldown: 0,
    kickCount: 0,
    finishedHorseCount: 0,
    _tier2Applied: false,
    _tier3Applied: false
  };
}

