describe('Win Conditions', () => {

  beforeEach(() => {
    ElementalHunter.init(TEST_CONFIG);
    gv.bus.emit.mockClear();
  });

  test('KO: When opponent HP <= 0, opponent loses immediately', () => {
    var board = createMockBoard({});
    var p0 = createPlayer(0);
    var p1 = createPlayer(1);
    p1.hp = 50;
    p0.tokens[0].atk = 100;
    p0.tokens[0].position = 5;
    p1.tokens[0].position = 5; // same tile to trigger kick
    var gameState = { board: board, players: { 0: p0, 1: p1 } };

    ElementalHunter.execute(gameState, { playerId: 0, tokenId: '0-t0', diceRoll: 0 });

    expect(p1.hp).toBe(-50);
    // The engine should detect KO and end match. Module only applies damage.
    expect(p1.hp <= 0).toBe(true);
  });

});

describe('Artifact Effects', () => {

  beforeEach(() => {
    ElementalHunter.init(TEST_CONFIG);
    gv.bus.emit.mockClear();
  });

  test('Apply Artifact Swap: swaps two adjacent elements', () => {
    var player = createPlayer(0);
    player.elementQueue = ['fire', 'ice', 'grass'];
    ElementalHunter.applyArtifact(player, 'Swap', { idx1: 0, idx2: 1 });

    expect(player.elementQueue).toEqual(['ice', 'fire', 'grass']);
    expect(gv.bus.emit).toHaveBeenCalledWith('elementalHunter:artifactApplied', expect.objectContaining({ artifactType: 'Swap' }));
  });

  test('Apply Artifact Swap with non-adjacent indices: ignored', () => {
    var player = createPlayer(0);
    player.elementQueue = ['fire', 'ice', 'grass'];
    ElementalHunter.applyArtifact(player, 'Swap', { idx1: 0, idx2: 2 });

    expect(player.elementQueue).toEqual(['fire', 'ice', 'grass']);
  });

  test('Apply Artifact Change: changes element at index to different valid element', () => {
    var player = createPlayer(0);
    player.elementQueue = ['fire', 'ice'];
    ElementalHunter.applyArtifact(player, 'Change', { index: 1, newElement: 'rock' });

    expect(player.elementQueue).toEqual(['fire', 'rock']);
    expect(gv.bus.emit).toHaveBeenCalledWith('elementalHunter:artifactApplied', expect.objectContaining({ artifactType: 'Change' }));
  });

  test('Apply Artifact Change to same element: ignored (must differ)', () => {
    var player = createPlayer(0);
    player.elementQueue = ['fire', 'ice'];
    ElementalHunter.applyArtifact(player, 'Change', { index: 1, newElement: 'fire' });

    expect(player.elementQueue).toEqual(['fire', 'ice']);
    // Should not emit
    expect(gv.bus.emit).not.toHaveBeenCalledWith('elementalHunter:artifactApplied', expect.anything());
  });

  test('Apply Artifact Charge: adds affinity element to end and triggers combo processing', () => {
    var player = createPlayer(0, { affinity: 'fire' });
    player.elementQueue = ['fire', 'fire', 'fire'];
    player.tokens[0].atk = 0;
    TEST_CONFIG.maxElementQueue = 10;
    ElementalHunter.init(TEST_CONFIG);
    // processCombos will be called;Charge should add 'fire' then call _processCombos.
    ElementalHunter.applyArtifact(player, 'Charge');

    expect(player.elementQueue).toContain('fire'); // new fire at end
    expect(player.elementQueue.length).toBe(4);
    // C3 should trigger after charge, removing the triple and applying bonuses
    // We'll check that combos were processed: _processCombos is private but it's called by applyArtifact
    // We can check token ATK increase:
    expect(player.tokens[0].atk).toBeGreaterThan(0);
    expect(player.comboCount).toBe(1);
  });

});

